let currentAvatarId = null;

function getUserAvatarId(addr) {
    const account = getAccountData(addr);
    return (account && account.avatarId !== undefined) ? account.avatarId : null;
}

function setUserAvatarId(addr, id) {
    const account = getAccountData(addr) || {};
    account.avatarId = id;
    setAccountData(addr, account);
}

function getPeerAvatarId(addr) {
    try {
        const raw = localStorage.getItem('w3m_peer_avatar_' + addr.toLowerCase());
        return raw !== null ? parseInt(raw) : null;
    } catch(e) { return null; }
}

function getAvatarColor(addr) {
    let hash = 0;
    const s = (addr || '').toLowerCase();
    for (let i = 0; i < s.length; i++) hash = ((hash << 5) - hash) + s.charCodeAt(i);
    return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

function getInitials(name) {
    if (!name) return '?';
    const parts = name.trim().split(/\s+/);
    if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
    return name.slice(0, 2).toUpperCase();
}

function shortAddr(addr) {
    if (!addr) return '';
    return addr.slice(0, 6) + '...' + addr.slice(-4);
}

function escHtml(s) {
    return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function formatTime(ts) {
    const d = new Date(ts * 1000);
    return d.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
}

function formatDate(ts) {
    const d = new Date(ts * 1000);
    const today = new Date();
    if (d.toDateString() === today.toDateString()) return 'Сегодня';
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    if (d.toDateString() === yesterday.toDateString()) return 'Вчера';
    return d.toLocaleDateString('ru-RU', { day: 'numeric', month: 'long' });
}

const contactsStore = {
    list: [],
    load() { try { const s = localStorage.getItem('w3m_contacts_' + userAddress); if (s) this.list = JSON.parse(s); } catch(e){} },
    save() { try { localStorage.setItem('w3m_contacts_' + userAddress, JSON.stringify(this.list)); } catch(e){} },
    add(c) {
        const addr = c.address.toLowerCase();
        if (!this.list.find(x => x.address.toLowerCase() === addr)) {
            this.list.push(c); this.save(); return true;
        }
        return false;
    },
    remove(addr) {
        const i = this.list.findIndex(c => c.address.toLowerCase() === addr.toLowerCase());
        if (i !== -1) { this.list.splice(i, 1); this.save(); return true; }
        return false;
    },
    find(addr) { return this.list.find(c => c.address.toLowerCase() === addr.toLowerCase()); },
    getName(addr) {
        const c = this.find(addr);
        return c ? c.name : shortAddr(addr);
    }
};

function showToast(msg, type = 'info') {
    const c = document.getElementById('toast-container');
    const d = document.createElement('div');
    d.className = 'toast ' + type;
    d.textContent = msg;
    c.appendChild(d);
    setTimeout(() => { d.style.opacity = '0'; setTimeout(() => d.remove(), 380); }, 3000);
}

// ====================== CRYPTO (DH E2E) ======================
async function deriveMasterKey(password, addr) {
    const salt = 'w3m-master-' + (addr || userAddress).toLowerCase();
    const enc = new TextEncoder();
    const keyMaterial = await crypto.subtle.importKey("raw", enc.encode(password), { name: "PBKDF2" }, false, ["deriveBits"]);
    const keyBits = await crypto.subtle.deriveBits({ name: "PBKDF2", salt: enc.encode(salt), iterations: 100000, hash: "SHA-256" }, keyMaterial, 256);
    return new Uint8Array(keyBits);
}

function encryptSigWithMaster(sig) {
    if (!masterKey) return null;
    const sigBytes = new TextEncoder().encode(sig);
    const nonce = nacl.randomBytes(24);
    const key32 = masterKey.length >= 32 ? masterKey.slice(0, 32) : masterKey;
    const encrypted = nacl.secretbox(sigBytes, nonce, key32);
    const combined = new Uint8Array(24 + encrypted.length);
    combined.set(nonce);
    combined.set(encrypted, 24);
    return Array.from(combined).map(b => b.toString(16).padStart(2, '0')).join('');
}

function decryptSigWithMaster(hex) {
    if (!masterKey || !hex) return null;
    try {
        const bytes = new Uint8Array(hex.match(/.{2}/g).map(h => parseInt(h, 16)));
        const nonce = bytes.slice(0, 24);
        const encrypted = bytes.slice(24);
        const key32 = masterKey.length >= 32 ? masterKey.slice(0, 32) : masterKey;
        const decrypted = nacl.secretbox.open(encrypted, nonce, key32);
        if (!decrypted) return null;
        return new TextDecoder().decode(decrypted);
    } catch(e) { return null; }
}

async function deriveE2EKeyPair() {
    if (!signer) return null;
    try {
        const cacheKey = 'w3m_e2e_sig_' + userAddress.toLowerCase();
        let sig = null;
        const cachedHex = localStorage.getItem(cacheKey);
        if (cachedHex && masterKey) {
            sig = decryptSigWithMaster(cachedHex);
        }
        if (!sig) {
            sig = await signer.signMessage('Web3Messenger-E2E-KeyPair-v1');
            if (masterKey) {
                const encHex = encryptSigWithMaster(sig);
                if (encHex) localStorage.setItem(cacheKey, encHex);
            }
        }
        const hash = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(sig));
        const secretKey = new Uint8Array(hash);
        e2eKeyPair = nacl.box.keyPair.fromSecretKey(secretKey);
        console.log('E2E keypair derived' + (cachedHex && sig ? ' (cached)' : ' (new sign)'));
        return e2eKeyPair;
    } catch(e) {
        console.error('E2E keypair derivation failed:', e);
        return null;
    }
}

async function initPubKeyRegistry() {
    const addr = getPubKeyRegistryAddress();
    if (!addr || !ethers.utils.isAddress(addr)) return null;
    pubKeyRegistryContract = new ethers.Contract(addr, PUBKEY_REGISTRY_ABI, signer);
    return pubKeyRegistryContract;
}

async function registerPublicKey() {
    if (!pubKeyRegistryContract || !e2eKeyPair) return;
    try {
        const hasKey = await pubKeyRegistryContract.hasKey(userAddress);
        if (hasKey) {
            const existing = await pubKeyRegistryContract.getKey(userAddress);
            const existingBytes = ethers.utils.arrayify(existing);
            if (nacl.verify(existingBytes, e2eKeyPair.publicKey)) {
                console.log('Public key already registered');
                return;
            }
        }
        const tx = await pubKeyRegistryContract.registerKey(e2eKeyPair.publicKey);
        await tx.wait();
        console.log('Public key registered on-chain');
        showToast('E2E ключ зарегистрирован', 'success');
    } catch(e) {
        console.error('registerPublicKey error:', e);
    }
}

function savePeerPubKey(peerAddr, pubKeyBytes) {
    const hex = Array.from(pubKeyBytes).map(b => b.toString(16).padStart(2, '0')).join('');
    localStorage.setItem('w3m_peer_pub_' + peerAddr.toLowerCase(), hex);
}

function loadPeerPubKey(peerAddr) {
    const hex = localStorage.getItem('w3m_peer_pub_' + peerAddr.toLowerCase());
    if (!hex || hex.length !== 64) return null;
    return new Uint8Array(hex.match(/.{2}/g).map(b => parseInt(b, 16)));
}

function saveOwnPubKey() {
    if (!e2eKeyPair || !userAddress) return;
    const hex = Array.from(e2eKeyPair.publicKey).map(b => b.toString(16).padStart(2, '0')).join('');
    localStorage.setItem('w3m_own_pub_' + userAddress.toLowerCase(), hex);
}

async function getPeerPublicKey(peerAddr) {
    const localKey = loadPeerPubKey(peerAddr);
    if (localKey) return localKey;

    if (pubKeyRegistryContract) {
        try {
            const key = await pubKeyRegistryContract.getKey(peerAddr);
            if (key && key !== ethers.constants.HashZero) {
                const bytes = ethers.utils.arrayify(key);
                savePeerPubKey(peerAddr, bytes);
                return bytes;
            }
        } catch(e) {
            console.error('getPeerPublicKey registry error:', e);
        }
    }
    return null;
}

async function getSharedSecret(peerAddr) {
    const cacheKey = peerAddr.toLowerCase();
    if (sharedKeyCache[cacheKey]) return sharedKeyCache[cacheKey];

    if (!e2eKeyPair) return null;
    const peerPub = await getPeerPublicKey(peerAddr);
    if (!peerPub) return null;

    const shared = nacl.box.before(peerPub, e2eKeyPair.secretKey);
    sharedKeyCache[cacheKey] = shared;
    return shared;
}

async function getAddressKey(peer) {
    const sorted = [userAddress.toLowerCase(), peer.toLowerCase()].sort().join(':web3m:');
    const hash = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(sorted));
    return new Uint8Array(hash);
}

async function getChatKey(peer) {
    const shared = await getSharedSecret(peer);
    if (shared) return { key: shared, mode: 'dh' };

    const addrKey = await getAddressKey(peer);
    return { key: addrKey, mode: 'addr' };
}

async function encrypt(text, peer) {
    const nonce = nacl.randomBytes(nacl.secretbox.nonceLength);
    const msg = new TextEncoder().encode(text);
    const addrKey = await getAddressKey(peer);
    const box = nacl.secretbox(msg, nonce, addrKey);

    if (e2eKeyPair) {
        const combined = new Uint8Array(1 + 32 + nonce.length + box.length);
        combined[0] = 0x01;
        combined.set(e2eKeyPair.publicKey, 1);
        combined.set(nonce, 33);
        combined.set(box, 33 + nonce.length);
        return btoa(String.fromCharCode.apply(null, combined));
    }

    const combined = new Uint8Array(nonce.length + box.length);
    combined.set(nonce);
    combined.set(box, nonce.length);
    return btoa(String.fromCharCode.apply(null, combined));
}

async function decrypt(encBase64, peer) {
    try {
        const data = atob(encBase64);
        const combined = new Uint8Array(data.length);
        for (let i = 0; i < data.length; i++) combined[i] = data.charCodeAt(i);

        let nonce, box, embeddedPubKey = null;
        let version = 0;

        if (combined.length > 59 && combined[0] === 0x03) {
            version = 0x03;
            embeddedPubKey = combined.slice(1, 33);
            nonce = combined.slice(33, 57);
            const dhLen = (combined[57] << 8) | combined[58];
            const dhBox = combined.slice(59, 59 + dhLen);
            const addrBox = combined.slice(59 + dhLen);

            if (embeddedPubKey.length === 32) {
                savePeerPubKey(peer, embeddedPubKey);
                delete sharedKeyCache[peer.toLowerCase()];
            }

            if (e2eKeyPair) {
                const dhShared = nacl.box.before(embeddedPubKey, e2eKeyPair.secretKey);
                const dec = nacl.secretbox.open(dhBox, nonce, dhShared);
                if (dec) return new TextDecoder().decode(dec);
            }

            const addrKey = await getAddressKey(peer);
            const decAddr = nacl.secretbox.open(addrBox, nonce, addrKey);
            if (decAddr) return new TextDecoder().decode(decAddr);

            return null;
        }

        if (combined.length > 33 + nacl.secretbox.nonceLength && (combined[0] === 0x01 || combined[0] === 0x02)) {
            version = combined[0];
            embeddedPubKey = combined.slice(1, 33);
            nonce = combined.slice(33, 33 + nacl.secretbox.nonceLength);
            box = combined.slice(33 + nacl.secretbox.nonceLength);

            if (embeddedPubKey && embeddedPubKey.length === 32) {
                savePeerPubKey(peer, embeddedPubKey);
                delete sharedKeyCache[peer.toLowerCase()];
            }
        } else {
            nonce = combined.slice(0, nacl.secretbox.nonceLength);
            box = combined.slice(nacl.secretbox.nonceLength);
        }

        if (e2eKeyPair && embeddedPubKey) {
            const dhShared = nacl.box.before(embeddedPubKey, e2eKeyPair.secretKey);
            const dec = nacl.secretbox.open(box, nonce, dhShared);
            if (dec) return new TextDecoder().decode(dec);
        }

        const addrKey = await getAddressKey(peer);
        const decAddr = nacl.secretbox.open(box, nonce, addrKey);
        if (decAddr) return new TextDecoder().decode(decAddr);

        const shared = await getSharedSecret(peer);
        if (shared) {
            const dec = nacl.secretbox.open(box, nonce, shared);
            if (dec) return new TextDecoder().decode(dec);
        }

        if (masterKey) {
            const sorted = [userAddress.toLowerCase(), peer.toLowerCase()].sort().join(':');
            const cryptoKey = await crypto.subtle.importKey("raw", masterKey, { name: "HMAC", hash: "SHA-256" }, false, ["sign"]);
            const sig = await crypto.subtle.sign("HMAC", cryptoKey, new TextEncoder().encode(sorted));
            const oldKey = new Uint8Array(sig);
            const dec2 = nacl.secretbox.open(box, nonce, oldKey);
            if (dec2) return new TextDecoder().decode(dec2);
        }

        return null;
    } catch (e) { return null; }
}

// ====================== NICKNAME RESOLVER ======================
async function resolveNickname(addr) {
    const key = addr.toLowerCase();
    if (nicknameCache[key]) return nicknameCache[key];
    try {
        if (identityContract) {
            const profile = await identityContract.getProfile(addr);
            const username = profile[0];
            if (username && username.trim().length > 0) {
                nicknameCache[key] = username.trim();
                return nicknameCache[key];
            }
        }
    } catch(e) {}
    const localAccount = getAccountData(addr);
    if (localAccount && localAccount.username) {
        nicknameCache[key] = localAccount.username;
        return nicknameCache[key];
    }
    return null;
}

async function resolveAndUpdateContact(addr) {
    const nick = await resolveNickname(addr);
    if (nick) {
        const contact = contactsStore.find(addr);
        if (contact && (contact.name === shortAddr(addr) || !contact.name || contact.name.endsWith('(' + shortAddr(addr) + ')'))) {
            contact.name = nick;
            contactsStore.save();
            return true;
        }
    }
    return false;
}

// ====================== ACCOUNT DATA ======================
function getAccountData(addr) {
    try {
        const raw = localStorage.getItem('w3m_account_' + addr.toLowerCase());
        return raw ? JSON.parse(raw) : null;
    } catch(e) { return null; }
}

function setAccountData(addr, data) {
    localStorage.setItem('w3m_account_' + addr.toLowerCase(), JSON.stringify(data));
}

function isRegistered(addr) {
    return !!getAccountData(addr);
}

async function verifyPassword(addr, password) {
    const account = getAccountData(addr);
    if (!account) return false;
    const key = await deriveMasterKey(password, addr);
    const hash = Array.from(key).map(b => b.toString(16).padStart(2, '0')).join('');
    return hash === account.keyHash;
}

