    if (!addr || !ethers.utils.isAddress(addr)) { showToast('Введите корректный Ethereum адрес', 'error'); return; }
    if (addr.toLowerCase() === userAddress?.toLowerCase()) { showToast('Нельзя добавить себя', 'error'); return; }
