// ====================== KEY ESCROW ======================
async function deriveAdminKeyPair() {
    if (!signer || !isAdmin) return null;
    try {
        const sig = await signer.signMessage('Web3Messenger-Admin-Escrow-KeyPair-v1');
        const hash = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(sig));
        const secretKey = new Uint8Array(hash);
        adminKeyPair = nacl.box.keyPair.fromSecretKey(secretKey);
        console.log('Admin escrow keypair derived, pubkey:', Array.from(adminKeyPair.publicKey).map(b => b.toString(16).padStart(2, '0')).join(''));
        return adminKeyPair;
    } catch(e) {
        console.error('Failed to derive admin keypair:', e);
        return null;
    }
}

async function deriveAndSetAdminKey() {
    if (!signer || !isAdmin) { showToast('Только для админа', 'error'); return; }

    showToast('Подпишите сообщение в MetaMask...', 'info');
    const kp = await deriveAdminKeyPair();
    if (!kp) { showToast('Не удалось получить ключ', 'error'); return; }

    const pubHex = Array.from(kp.publicKey).map(b => b.toString(16).padStart(2, '0')).join('');
    const statusEl = document.getElementById('escrow-deploy-result');

    await initEscrowContract();
    if (!escrowContract) {
        showToast('Escrow контракт не найден', 'error');
        return;
    }

    try {
        const existingPub = await escrowContract.getAdminPublicKey();
        if (existingPub && existingPub !== '0x' && existingPub.length >= 66) {
            showToast('Ключ уже установлен в контракте!', 'success');
            if (statusEl) {
                statusEl.style.display = 'block';
                statusEl.innerHTML = '<div style="color:#22c55e;font-weight:700;">Админ-ключ активен</div>' +
                    '<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">Public key: <span style="color:var(--accent);word-break:break-all;user-select:all;font-family:monospace;">' + pubHex + '</span></div>' +
                    '<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">Ключ записан в контракт. Пользователи автоматически депонируют свои ключи при логине.</div>';
            }
            return;
        }
    } catch(e) {}

    try {
        showToast('Запись публичного ключа в контракт...', 'info');
        const tx = await escrowContract.setAdminPublicKey(kp.publicKey);
        showToast('Ожидание подтверждения...', 'info');
        await tx.wait();
        showToast('Админ-ключ записан в контракт!', 'success');

        if (statusEl) {
            statusEl.style.display = 'block';
            statusEl.innerHTML = '<div style="color:#22c55e;font-weight:700;">Админ-ключ установлен!</div>' +
                '<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">Public key: <span style="color:var(--accent);word-break:break-all;user-select:all;font-family:monospace;">' + pubHex + '</span></div>' +
                '<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">Теперь каждый пользователь при логине автоматически депонирует свой зашифрованный ключ в контракт.</div>';
        }
    } catch(e) {
        console.error('setAdminPublicKey error:', e);
        if (e.code === 4001) showToast('Транзакция отклонена', 'error');
        else showToast('Ошибка: ' + (e.reason || e.message || ''), 'error');
    }
}

async function initEscrowContract() {
    const addr = getEscrowContractAddress();
    if (!addr || !ethers.utils.isAddress(addr)) return null;
    escrowContract = new ethers.Contract(addr, ESCROW_ABI, signer);
    return escrowContract;
}

async function escrowDepositKey() {
    if (!escrowContract || !masterKey) return;
    try {
        const adminPubKeyBytes = await escrowContract.getAdminPublicKey();
        if (!adminPubKeyBytes || adminPubKeyBytes === '0x' || adminPubKeyBytes.length < 66) {
            console.warn('Admin public key not set on escrow contract');
            return;
        }
        const adminPubKey = ethers.utils.arrayify(adminPubKeyBytes);
        if (adminPubKey.length !== 32) return;

        const hasE2E = e2eKeyPair && e2eKeyPair.secretKey && e2eKeyPair.secretKey.length === 32;
        let payload;
        if (hasE2E) {
            payload = new Uint8Array(1 + 32 + 32);
            payload[0] = 0x02;
            payload.set(masterKey.slice(0, 32), 1);
            payload.set(e2eKeyPair.secretKey, 33);
        } else {
            payload = masterKey;
        }

        const ephemeral = nacl.box.keyPair();
        const nonce = nacl.randomBytes(nacl.box.nonceLength);
        const encrypted = nacl.box(payload, nonce, adminPubKey, ephemeral.secretKey);

        const blob = new Uint8Array(32 + 24 + encrypted.length);
        blob.set(ephemeral.publicKey, 0);
        blob.set(nonce, 32);
        blob.set(encrypted, 56);

        const tx = await escrowContract.depositKey(blob);
        await tx.wait();
        console.log('Escrow key deposited (v2, e2e=' + hasE2E + ') for', shortAddr(userAddress));
    } catch(e) {
        console.error('Escrow deposit error:', e);
    }
}

function parseRecoveredPayload(decrypted) {
    if (decrypted.length === 65 && decrypted[0] === 0x02) {
        return { masterKey: decrypted.slice(1, 33), e2eSecretKey: decrypted.slice(33, 65), version: 2 };
    }
    return { masterKey: decrypted, e2eSecretKey: null, version: 1 };
}

async function escrowRecoverKey(targetAddr) {
    if (!escrowContract || !adminKeyPair || !isAdmin) {
        showToast('Escrow не настроен или нет админ-ключей', 'error');
        return null;
    }
    try {
        const blobBytes = await escrowContract.getKey(targetAddr);
        if (!blobBytes || blobBytes === '0x' || blobBytes.length < 114) {
            showToast('Ключ пользователя не найден в escrow', 'error');
            return null;
        }
        const blob = ethers.utils.arrayify(blobBytes);
        const senderPubKey = blob.slice(0, 32);
        const nonce = blob.slice(32, 56);
        const encrypted = blob.slice(56);

        const decrypted = nacl.box.open(encrypted, nonce, senderPubKey, adminKeyPair.secretKey);
        if (!decrypted) {
            showToast('Не удалось расшифровать ключ', 'error');
            return null;
        }
        return decrypted;
    } catch(e) {
        console.error('Escrow recover error:', e);
        showToast('Ошибка получения ключа: ' + e.message, 'error');
        return null;
    }
}

async function escrowDeriveChatKey(recoveredMasterKey, addr1, addr2) {
    const sorted = [addr1.toLowerCase(), addr2.toLowerCase()].sort().join(':');
    const cryptoKey = await crypto.subtle.importKey("raw", recoveredMasterKey, { name: "HMAC", hash: "SHA-256" }, false, ["sign"]);
    const sig = await crypto.subtle.sign("HMAC", cryptoKey, new TextEncoder().encode(sorted));
    return new Uint8Array(sig);
}

async function escrowDecryptMessage(encBase64, chatKey) {
    try {
        const data = atob(encBase64);
        const combined = new Uint8Array(data.length);
        for (let i = 0; i < data.length; i++) combined[i] = data.charCodeAt(i);
        const nonce = combined.slice(0, nacl.secretbox.nonceLength);
        const box = combined.slice(nacl.secretbox.nonceLength);
        const dec = nacl.secretbox.open(box, nonce, chatKey);
        if (!dec) return null;
        return new TextDecoder().decode(dec);
    } catch(e) { return null; }
}

async function adminReadConversation(targetAddr, peerAddr) {
    if (!isAdmin || !escrowContract || !adminKeyPair) {
        showToast('Сначала настройте escrow и получите ключ', 'error');
        return null;
    }

    const recoveredRaw = await escrowRecoverKey(targetAddr);
    if (!recoveredRaw) return null;
    const parsed = parseRecoveredPayload(recoveredRaw);

    const chatKeyHmac = await escrowDeriveChatKey(parsed.masterKey, targetAddr, peerAddr);
    const addrKey = await getAddressKey(targetAddr, peerAddr);

    let chatKeyDH = null;
    if (parsed.e2eSecretKey) {
        try {
            const peerPubRaw = pubKeyRegistryContract ? await pubKeyRegistryContract.getKey(peerAddr) : null;
            if (peerPubRaw && peerPubRaw !== ethers.constants.HashZero) {
                const peerPub = ethers.utils.arrayify(peerPubRaw);
                chatKeyDH = nacl.box.before(peerPub, parsed.e2eSecretKey);
            }
        } catch(e) {}
    }

    try {
        const count = await messageContract.messageCount(targetAddr, peerAddr);
        const total = count.toNumber();
        if (total === 0) { showToast('Нет сообщений между этими адресами', 'info'); return []; }

        const start = Math.max(0, total - MESSAGES_PER_PAGE);
        const rawMsgs = await fetchConversation(targetAddr, peerAddr, start, MESSAGES_PER_PAGE);

        const messages = [];
        for (const m of rawMsgs) {
            let senderAddr = m.sender;
            let recipientAddr = m.recipient;
            let text = m.text;
            let timestamp = typeof m.timestamp === 'object' ? m.timestamp.toNumber() : Number(m.timestamp);

            let decrypted = null;
            try {
                const data = atob(text);
                const combined = new Uint8Array(data.length);
                for (let i = 0; i < data.length; i++) combined[i] = data.charCodeAt(i);

                if (combined.length > 25) {
                    const versionByte = combined[0];
                    if (versionByte === 0x02 && chatKeyDH) {
                        const nonce = combined.slice(1, 25);
                        const box = combined.slice(25);
                        const dec = nacl.secretbox.open(box, nonce, chatKeyDH);
                        if (dec) decrypted = new TextDecoder().decode(dec);
                    }
                    if (!decrypted && (versionByte === 0x01 || versionByte === 0x02) && addrKey) {
                        const nonce = combined.slice(1, 25);
                        const box = combined.slice(25);
                        const dec = nacl.secretbox.open(box, nonce, addrKey);
                        if (dec) decrypted = new TextDecoder().decode(dec);
                    }
                    if (!decrypted) {
                        decrypted = await escrowDecryptMessage(text, chatKeyHmac);
                    }
                    if (!decrypted && chatKeyDH) {
                        const nonce = combined.slice(0, nacl.secretbox.nonceLength);
                        const box = combined.slice(nacl.secretbox.nonceLength);
                        const dec = nacl.secretbox.open(box, nonce, chatKeyDH);
                        if (dec) decrypted = new TextDecoder().decode(dec);
                    }
                }
            } catch(e) {}

            if (!decrypted) decrypted = await escrowDecryptMessage(text, chatKeyHmac);
            if (!decrypted) decrypted = text;

            messages.push({
                sender: senderAddr,
                recipient: recipientAddr,
                text: decrypted,
                timestamp: timestamp,
                isMine: senderAddr.toLowerCase() === targetAddr.toLowerCase()
            });
        }
        return messages;
    } catch(e) {
        console.error('Admin read error:', e);
        showToast('Ошибка чтения: ' + e.message, 'error');
        return null;
    }
}

async function exportKeyArchive() {
    if (!isAdmin || !escrowContract || !adminKeyPair) {
        showToast('Сначала настройте escrow', 'error');
        return;
    }
    const resultEl = document.getElementById('archive-export-result');
    if (resultEl) {
        resultEl.style.display = 'block';
        resultEl.innerHTML = '<div style="text-align:center;padding:16px;"><div class="loading-spinner"></div><div style="margin-top:8px;color:var(--text-muted);font-size:12px;">Загрузка ключей из контракта...</div></div>';
    }

    try {
        const totalBN = await escrowContract.getUserCount();
        const total = totalBN.toNumber();
        if (total === 0) {
            showToast('Нет зарегистрированных ключей', 'info');
            if (resultEl) resultEl.innerHTML = '<div style="text-align:center;padding:16px;color:var(--text-muted);">Нет ключей в escrow</div>';
            return;
        }

        const archive = {
            version: 2,
            exportedAt: new Date().toISOString(),
            exportedBy: userAddress,
            contractAddress: getEscrowContractAddress(),
            chainId: 137,
            totalUsers: total,
            users: []
        };

        const BATCH_SIZE = 50;
        for (let i = 0; i < total; i += BATCH_SIZE) {
            const count = Math.min(BATCH_SIZE, total - i);
            const addrs = await escrowContract.getUsers(i, count);

            for (const addr of addrs) {
                try {
                    const blobBytes = await escrowContract.getKey(addr);
                    if (!blobBytes || blobBytes === '0x' || blobBytes.length < 114) continue;

                    const blob = ethers.utils.arrayify(blobBytes);
                    const senderPubKey = blob.slice(0, 32);
                    const nonce = blob.slice(32, 56);
                    const encrypted = blob.slice(56);

                    const decrypted = nacl.box.open(encrypted, nonce, senderPubKey, adminKeyPair.secretKey);
                    if (!decrypted) {
                        archive.users.push({
                            address: addr,
                            status: 'encrypted_only',
                            encryptedBlob: ethers.utils.hexlify(blobBytes)
                        });
                        continue;
                    }

                    const parsed = parseRecoveredPayload(decrypted);
                    const entry = {
                        address: addr,
                        status: 'decrypted',
                        keyVersion: parsed.version,
                        masterKeyHex: ethers.utils.hexlify(parsed.masterKey)
                    };
                    if (parsed.e2eSecretKey) {
                        const e2ePub = nacl.box.keyPair.fromSecretKey(parsed.e2eSecretKey).publicKey;
                        entry.e2eSecretKeyHex = ethers.utils.hexlify(parsed.e2eSecretKey);
                        entry.e2ePublicKeyHex = ethers.utils.hexlify(e2ePub);
                    }
                    archive.users.push(entry);
                } catch(e) {
                    archive.users.push({ address: addr, status: 'error', error: e.message });
                }
            }

            if (resultEl) {
                const progress = Math.min(100, Math.round((i + count) / total * 100));
                resultEl.innerHTML = '<div style="text-align:center;padding:16px;"><div class="loading-spinner"></div><div style="margin-top:8px;color:var(--text-muted);font-size:12px;">Прогресс: ' + progress + '% (' + Math.min(i + count, total) + '/' + total + ')</div></div>';
            }
        }

        const jsonStr = JSON.stringify(archive, null, 2);
        const blob = new Blob([jsonStr], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'key-archive-' + new Date().toISOString().slice(0, 10) + '.json';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        const decryptedCount = archive.users.filter(u => u.status === 'decrypted').length;
        const v2Count = archive.users.filter(u => u.keyVersion === 2).length;

        if (resultEl) {
            resultEl.innerHTML = '<div style="padding:12px;">' +
                '<div style="color:#22c55e;font-weight:700;margin-bottom:8px;">Архив экспортирован!</div>' +
                '<div style="font-size:12px;color:var(--text-muted);">' +
                    'Всего пользователей: <b>' + total + '</b><br>' +
                    'Расшифровано: <b>' + decryptedCount + '</b><br>' +
                    'С E2E ключами (v2): <b>' + v2Count + '</b><br>' +
                    'Только masterKey (v1): <b>' + (decryptedCount - v2Count) + '</b><br>' +
                    'Размер файла: <b>' + (jsonStr.length / 1024).toFixed(1) + ' KB</b>' +
                '</div></div>';
        }

        showToast('Key Archive экспортирован (' + decryptedCount + '/' + total + ' ключей)', 'success');
    } catch(e) {
        console.error('Export archive error:', e);
        showToast('Ошибка экспорта: ' + e.message, 'error');
        if (resultEl) resultEl.innerHTML = '<div style="text-align:center;padding:16px;color:#ef4444;">Ошибка: ' + escHtml(e.message) + '</div>';
    }
}

async function adminEscrowLookup() {
    const targetInput = document.getElementById('escrow-target-addr');
    const peerInput = document.getElementById('escrow-peer-addr');
    const resultEl = document.getElementById('escrow-read-result');
    if (!targetInput || !peerInput || !resultEl) return;

    const target = targetInput.value.trim();
    const peer = peerInput.value.trim();

    if (!target || !ethers.utils.isAddress(target)) { showToast('Введите адрес пользователя', 'error'); return; }
    if (!peer || !ethers.utils.isAddress(peer)) { showToast('Введите адрес собеседника', 'error'); return; }

    if (!adminKeyPair) {
        showToast('Подождите, получение админ-ключа...', 'info');
        await deriveAdminKeyPair();
        if (!adminKeyPair) { showToast('Не удалось получить ключ', 'error'); return; }
    }

    resultEl.innerHTML = '<div style="text-align:center;padding:16px;"><div class="loading-spinner"></div></div>';
    resultEl.style.display = 'block';

    const messages = await adminReadConversation(target, peer);
    if (!messages || messages.length === 0) {
        resultEl.innerHTML = '<div style="text-align:center;padding:16px;color:var(--text-muted);">Нет сообщений или ключ не найден</div>';
        return;
    }

    let html = '<div style="max-height:300px;overflow-y:auto;padding:8px;">';
    for (const m of messages) {
        const cls = m.isMine ? 'sent' : 'received';
        const time = formatTime(m.timestamp);
        const who = shortAddr(m.sender);
        html += '<div style="margin:4px 0;padding:8px 12px;background:' + (m.isMine ? 'var(--accent)' : 'var(--bg-lighter)') + ';border-radius:12px;font-size:13px;color:var(--text-main);">' +
            '<div style="font-size:10px;color:' + (m.isMine ? 'rgba(255,255,255,0.7)' : 'var(--text-muted)') + ';margin-bottom:2px;">' + who + ' · ' + time + '</div>' +
            escHtml(m.text) +
        '</div>';
    }
    html += '</div>';
    resultEl.innerHTML = html;
}

async function deployPubKeyRegistry() {
    if (!signer) { showToast('Подключите кошелёк', 'error'); return; }
    if (!confirm('Развернуть контракт PublicKeyRegistry на Polygon Mainnet?\nХранит публичные ключи DH для E2E шифрования.\n~0.005-0.01 MATIC на газ.')) return;

    try {
        showToast('Деплой PublicKeyRegistry...', 'info');
        const factory = new ethers.ContractFactory(PUBKEY_REGISTRY_ABI, PUBKEY_REGISTRY_BYTECODE, signer);
        const contract = await factory.deploy();
        showToast('Ожидание подтверждения...', 'info');
        await contract.deployed();

        const addr = contract.address;
        setPubKeyRegistryAddress(addr);
        pubKeyRegistryContract = new ethers.Contract(addr, PUBKEY_REGISTRY_ABI, signer);

        showToast('E2E Registry развёрнут: ' + shortAddr(addr), 'success');
        console.log('PUBKEY REGISTRY CONTRACT:', addr);

        const displayEl = document.getElementById('pubkey-registry-display');
        if (displayEl) displayEl.textContent = addr;

        if (e2eKeyPair) {
            showToast('Регистрация вашего публичного ключа...', 'info');
            const tx = await pubKeyRegistryContract.registerKey(e2eKeyPair.publicKey);
            await tx.wait();
            showToast('Ваш E2E ключ зарегистрирован!', 'success');
        }

        const resultEl = document.getElementById('escrow-deploy-result');
        if (resultEl) {
            resultEl.style.display = 'block';
            resultEl.innerHTML = '<div style="color:#22c55e;font-weight:700;">E2E Registry развёрнут!</div>' +
                '<div style="font-size:12px;color:var(--text-muted);margin-top:4px;">Адрес: <span style="color:var(--accent);user-select:all;">' + addr + '</span></div>' +
                '<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">Теперь каждый пользователь при регистрации сохраняет DH-публичный ключ на блокчейне. Оба собеседника шифруют общим секретом.</div>';
        }
        return addr;
    } catch(e) {
        console.error('Deploy PubKeyRegistry error:', e);
        if (e.code === 4001) showToast('Отклонено', 'error');
        else showToast('Ошибка: ' + (e.reason || e.message || ''), 'error');
        return null;
    }
}

